use std::cmp::Reverse;

fn top_k_largest(nums: &[i32], k: usize) -> Vec<i32> {
    let mut heap = BinaryHeap::new();
    for &num in nums {
        heap.push(Reverse(num));
        if heap.len() > k {
            heap.pop();
        }
    }
    heap.into_iter().map(|Reverse(x)| x).collect()
}

fn main() {
    let mut result = top_k_largest(&[3, 1, 5, 2, 4, 8, 7], 3);
    result.sort();
    println!("{:?}", result);  // [5, 7, 8]
}

