fn main() {
    let nums = vec![5, 3, 8, 1, 9, 2];
    let mut heap = BinaryHeap::from(nums);

    println!("{:?}", heap.peek());  // Some(9)

    let mut sorted = Vec::new();
    while let Some(val) = heap.pop() {
        sorted.push(val);
    }
    println!("{:?}", sorted);  // [9, 8, 5, 3, 2, 1]
}

